sql:
SELECT COUNT(release_id) AS active_beta_releases
FROM python_releases
WHERE is_active = 1 AND status = 'beta';

SELECT url
FROM release_links
WHERE download_count = (SELECT MAX(download_count) FROM release_links);

external_knowledge:
; Python release versions typically follow a format like "Major.Minor.Micro", where "Major" is the major version, "Minor" is the minor version, and "Micro" is the micro version (e.g., "3.9.5"); 
; The cumulative download count refers to the total number of times the release has been downloaded, including all its child releases;
; The latest deployment date refers to the most recent date when the release was deployed for a project.

sql:
SELECT MAX(release_date) AS latest_release_date
FROM python_releases
WHERE is_active = 1;

SELECT SUM(download_count) AS total_downloads
FROM release_links
WHERE release_id = 1;

SELECT download_count
FROM release_links
WHERE link_id = 1;

